class Solution {
public:
    int longestPalindrome(string s, string t) {
        string combined = s + t;
        int n = combined.size();
        vector<vector<bool>> dp(n, vector<bool>(n, false));
        int maxLen = 1;
        for (int i = n - 1; i >= 0; --i) {
            dp[i][i] = true;
            for (int j = i + 1; j < n; ++j) {
                if (combined[i] == combined[j]) {
                    if (j - i == 1 || dp[i + 1][j - 1]) {
                        dp[i][j] = true;
                        if (i < s.size() && j >= s.size()) {
                            maxLen = max(maxLen, j - i + 1);
                        }
                    }
                }
            }
        }
        return maxLen;
    }
};

